SELECT sentence
FROM voice_segments
WHERE gender = 'male';

SELECT gender, COUNT(*) AS total_segments
FROM voice_segments
GROUP BY gender;

SELECT COUNT(*) AS total_segments
FROM voice_segments
WHERE accent = 'american';

SELECT segment_id, confidence_score
FROM voice_segments
ORDER BY confidence_score DESC;

SELECT SUM(up_votes) AS total_up_votes, SUM(down_votes) AS total_down_votes
FROM voice_segments
WHERE provider_id = (SELECT provider_id FROM providers WHERE provider_name = 'Amazon');

SELECT sentence, confidence_score
FROM voice_segments
WHERE sentence_length BETWEEN 6 AND 10;
